import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const RaiseComplaint = () => {
    const [formData, setFormData] = useState({
        department: '', programme: '', block: '', blockName: '', roomNumber: '', 
        complaintType: 'PC Hardware', complaintRemarks: '', attachment: ''
    });
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [blocks, setBlocks] = useState([]);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchDepartments();
    }, []);

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching departments' });
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching programmes' });
        }
    };

    const fetchBlocks = async (progId) => {
        try {
            const { data } = await API.get('/master/block');
            const filtered = data.filter(b => b.programme && b.programme._id === progId);
            setBlocks(filtered);
            setFormData(prev => ({...prev, block: '', blockName: ''}));
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching blocks' });
        }
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFormData(prev => ({...prev, department: deptId, programme: '', block: ''}));
        if (deptId) fetchProgrammes(deptId);
    };

    const handleProgrammeChange = (e) => {
        const progId = e.target.value;
        setFormData(prev => ({...prev, programme: progId, block: ''}));
        if (progId) fetchBlocks(progId);
    };

    const handleBlockChange = (e) => {
        const blockId = e.target.value;
        const selectedBlock = blocks.find(b => b._id === blockId);
        setFormData(prev => ({...prev, block: blockId, blockName: selectedBlock?.blockName || ''}));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/complaints', formData);
            setMessage({ type: 'success', text: '✓ Ticket submitted successfully!' });
            setFormData({
                department: '', programme: '', block: '', blockName: '', roomNumber: '', 
                complaintType: 'PC Hardware', complaintRemarks: '', attachment: ''
            });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error raising ticket: ' + (err.response?.data?.error || err.message) });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>📝 Raise a New Ticket</h1>
                    <p style={styles.subtitle}>Submit a new support ticket or complaint</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success' 
                            ? 'rgba(16, 185, 129, 0.2)' 
                            : 'rgba(239, 68, 68, 0.2)',
                        borderColor: message.type === 'success' ? '#10b981' : '#ef4444',
                        color: message.type === 'success' ? '#a7f3d0' : '#fca5a5',
                    }}>
                        {message.text}
                    </div>
                )}

                <div style={styles.formWrapper}>
                    <div style={styles.formCard}>
                        <form onSubmit={handleSubmit} style={styles.form}>
                            <div style={styles.formGrid}>
                                <div style={styles.formGroup}>
                                    <label style={styles.label}>🏢 Department</label>
                                    <select 
                                        required
                                        value={formData.department}
                                        onChange={handleDepartmentChange}
                                        style={styles.select}
                                    >
                                        <option value="">Select Department</option>
                                        {departments.map(d => <option key={d._id} value={d._id}>{d.deptName}</option>)}
                                    </select>
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>📚 Programme</label>
                                    <select 
                                        required
                                        value={formData.programme}
                                        onChange={handleProgrammeChange}
                                        style={styles.select}
                                    >
                                        <option value="">Select Programme</option>
                                        {programmes.map(p => <option key={p._id} value={p._id}>{p.programmeName}</option>)}
                                    </select>
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>🏠 Block</label>
                                    <select 
                                        required
                                        value={formData.block}
                                        onChange={handleBlockChange}
                                        style={styles.select}
                                    >
                                        <option value="">Select Block</option>
                                        {blocks.map(b => <option key={b._id} value={b._id}>{b.blockName}</option>)}
                                    </select>
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>🚪 Room Number</label>
                                    <input 
                                        type="text" 
                                        placeholder="e.g., A101, B202..." 
                                        required 
                                        value={formData.roomNumber}
                                        onChange={e => setFormData({...formData, roomNumber: e.target.value})} 
                                        style={styles.input}
                                    />
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>🔧 Complaint Type</label>
                                    <select 
                                        value={formData.complaintType}
                                        onChange={e => setFormData({...formData, complaintType: e.target.value})} 
                                        style={styles.select}
                                    >
                                        <option value="PC Hardware">🖥️ PC Hardware</option>
                                        <option value="PC Software">💻 PC Software</option>
                                        <option value="Application Issues">⚙️ Application Issues</option>
                                        <option value="Network">🌐 Network</option>
                                        <option value="Electronics">⚡ Electronics</option>
                                        <option value="Plumbing">🔧 Plumbing</option>
                                    </select>
                                </div>
                            </div>

                            <div style={styles.formGroup}>
                                <label style={styles.label}>📋 Complaint Remarks</label>
                                <textarea 
                                    placeholder="Describe your issue in detail..." 
                                    required 
                                    value={formData.complaintRemarks}
                                    onChange={e => setFormData({...formData, complaintRemarks: e.target.value})} 
                                    style={{...styles.textarea}}
                                />
                            </div>

                            <div style={styles.formGroup}>
                                <label style={styles.label}>📎 Attachment URL (Optional)</label>
                                <input 
                                    type="url" 
                                    placeholder="https://example.com/image.jpg" 
                                    value={formData.attachment}
                                    onChange={e => setFormData({...formData, attachment: e.target.value})} 
                                    style={styles.input}
                                />
                            </div>

                            <button type="submit" disabled={loading} style={{...styles.button, opacity: loading ? 0.6 : 1}}>
                                {loading ? '⏳ Submitting Ticket...' : '🚀 Submit Ticket'}
                            </button>
                        </form>
                    </div>

                    <div style={styles.infoCard}>
                        <h3 style={styles.infoTitle}>📌 Quick Tips</h3>
                        <ul style={styles.tipsList}>
                            <li style={styles.tipItem}>Be as detailed as possible when describing your issue</li>
                            <li style={styles.tipItem}>Include the exact location and room number</li>
                            <li style={styles.tipItem}>Attach screenshots or images if available</li>
                            <li style={styles.tipItem}>Our team will respond within 24 hours</li>
                            <li style={styles.tipItem}>You'll receive email updates on your ticket status</li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    );
};

const styles = {
    pageWrapper: {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)',
        color: '#e0e7ff',
        fontFamily: "'Poppins', sans-serif",
    },
    contentArea: {
        maxWidth: '1200px',
        margin: '0 auto',
        padding: '40px 30px',
    },
    headerSection: {
        marginBottom: '40px',
    },
    mainTitle: {
        fontSize: '2.2rem',
        fontWeight: 800,
        background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        marginBottom: '10px',
    },
    subtitle: {
        fontSize: '1rem',
        color: '#94a3b8',
        fontWeight: 500,
    },
    alertBox: {
        padding: '16px 20px',
        borderRadius: '12px',
        border: '2px solid',
        marginBottom: '30px',
        fontWeight: 600,
    },
    formWrapper: {
        display: 'grid',
        gridTemplateColumns: '2fr 1fr',
        gap: '30px',
        alignItems: 'start',
    },
    formCard: {
        background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))',
        backdropFilter: 'blur(15px)',
        border: '2px solid rgba(51, 65, 85, 0.3)',
        borderRadius: '16px',
        padding: '32px',
        boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)',
    },
    form: {
        display: 'flex',
        flexDirection: 'column',
        gap: '24px',
    },
    formGrid: {
        display: 'grid',
        gridTemplateColumns: 'repeat(2, 1fr)',
        gap: '20px',
    },
    formGroup: {
        display: 'flex',
        flexDirection: 'column',
    },
    label: {
        fontSize: '0.95rem',
        fontWeight: 600,
        color: '#cbd5e1',
        marginBottom: '10px',
        letterSpacing: '0.3px',
    },
    input: {
        padding: '12px 16px',
        background: 'rgba(20, 28, 45, 0.6)',
        border: '2px solid rgba(51, 65, 85, 0.4)',
        borderRadius: '12px',
        color: '#fff',
        fontSize: '0.95rem',
        fontFamily: "'Poppins', sans-serif",
        transition: 'all 0.3s ease',
        boxSizing: 'border-box',
    },
    select: {
        padding: '12px 16px',
        background: 'rgba(20, 28, 45, 0.6)',
        border: '2px solid rgba(51, 65, 85, 0.4)',
        borderRadius: '12px',
        color: '#fff',
        fontSize: '0.95rem',
        fontFamily: "'Poppins', sans-serif",
        transition: 'all 0.3s ease',
        boxSizing: 'border-box',
        cursor: 'pointer',
    },
    textarea: {
        padding: '12px 16px',
        background: 'rgba(20, 28, 45, 0.6)',
        border: '2px solid rgba(51, 65, 85, 0.4)',
        borderRadius: '12px',
        color: '#fff',
        fontSize: '0.95rem',
        fontFamily: "'Poppins', sans-serif",
        transition: 'all 0.3s ease',
        boxSizing: 'border-box',
        minHeight: '140px',
        resize: 'vertical',
    },
    button: {
        padding: '14px 24px',
        background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
        border: 'none',
        borderRadius: '12px',
        color: 'white',
        fontSize: '0.95rem',
        fontWeight: 700,
        cursor: 'pointer',
        transition: 'all 0.3s ease',
        fontFamily: "'Poppins', sans-serif",
        boxShadow: '0 10px 30px -8px rgba(56, 189, 248, 0.3)',
        textTransform: 'uppercase',
        letterSpacing: '0.5px',
    },
    infoCard: {
        background: 'linear-gradient(135deg, rgba(56, 189, 248, 0.1), rgba(129, 140, 248, 0.1))',
        backdropFilter: 'blur(15px)',
        border: '2px solid rgba(56, 189, 248, 0.2)',
        borderRadius: '16px',
        padding: '28px',
        boxShadow: '0 25px 50px -12px rgba(56, 189, 248, 0.1)',
    },
    infoTitle: {
        fontSize: '1.2rem',
        fontWeight: 700,
        color: '#38bdf8',
        marginBottom: '16px',
    },
    tipsList: {
        listStyle: 'none',
        padding: 0,
        margin: 0,
    },
    tipItem: {
        padding: '10px 0',
        color: '#cbd5e1',
        fontSize: '0.9rem',
        borderBottom: '1px solid rgba(51, 65, 85, 0.2)',
        lineHeight: '1.6',
    },
};

export default RaiseComplaint;
